813:     ) {
814:         let raw_self_ty = self_ty.value.value;
815:         match *raw_self_ty.kind() {
816:             ty::Dynamic(data, ..) if let Some(p) = data.principal() => {
817:                 // Subtle: we can't use `instantiate_query_response` here: using it will
818:                 // commit to all of the type equalities assumed by inference going through
819:                 // autoderef (see the `method-probe-no-guessing` test).
820:                 //
821:                 // However, in this code, it is OK if we end up with an object type that is
822:                 // "more general" than the object type that we are evaluating. For *every*
823:                 // object type `MY_OBJECT`, a function call that goes through a trait-ref
824:                 // of the form `<MY_OBJECT as SuperTraitOf(MY_OBJECT)>::func` is a valid
825:                 // `ObjectCandidate`, and it should be discoverable "exactly" through one
826:                 // of the iterations in the autoderef loop, so there is no problem with it
827:                 // being discoverable in another one of these iterations.
828:                 //
829:                 // Using `instantiate_canonical` on our
830:                 // `Canonical<QueryResponse<Ty<'tcx>>>` and then *throwing away* the
