840:             }
841:             ty::Adt(def, _) => {
842:                 let def_id = def.did();
843:                 self.assemble_inherent_impl_candidates_for_type(def_id, receiver_steps);
844:                 self.assemble_inherent_candidates_for_incoherent_ty(raw_self_ty, receiver_steps);
845:             }
