1513:                             pick.autoref_or_ptr_adjustment =
1514:                                 Some(AutorefOrPtrAdjustment::ReborrowPin(*mutbl));
1515:                         }
1516:                     }
1517: 
1518:                     _ => (),
1519:                 }
1520: 
1521:                 pick
1522:             })
1523:         })
