2292:     /// Much like `collapse_candidates_to_trait_pick`, this method allows us to collapse
2293:     /// multiple conflicting picks if there is one pick whose trait container is a subtrait
2294:     /// of the trait containers of all of the other picks.
2295:     ///
2296:     /// This implements RFC #3624.
2297:     fn collapse_candidates_to_subtrait_pick(
2298:         &self,
2299:         self_ty: Ty<'tcx>,
2300:         probes: &[(&Candidate<'tcx>, ProbeResult)],
2301:     ) -> Option<Pick<'tcx>> {
2302:         let mut child_candidate = probes[0].0;
2303:         let mut child_trait = child_candidate.item.trait_container(self.tcx)?;
2304:         let mut supertraits: SsoHashSet<_> = supertrait_def_ids(self.tcx, child_trait).collect();
2305: 
2306:         let mut remaining_candidates: Vec<_> = probes[1..].iter().map(|&(p, _)| p).collect();
2307:         while !remaining_candidates.is_empty() {
2308:             let mut made_progress = false;
2309:             let mut next_round = vec![];
2310: 
2311:             for remaining_candidate in remaining_candidates {
2312:                 let remaining_trait = remaining_candidate.item.trait_container(self.tcx)?;
2313:                 if supertraits.contains(&remaining_trait) {
2314:                     made_progress = true;
2315:                     continue;
2316:                 }
2317: 
2318:                 // This pick is not a supertrait of the `child_pick`.
2319:                 // Check if it's a subtrait of the `child_pick`, instead.
2320:                 // If it is, then it must have been a subtrait of every
2321:                 // other pick we've eliminated at this point. It will
2322:                 // take over at this point.
2323:                 let remaining_trait_supertraits: SsoHashSet<_> =
2324:                     supertrait_def_ids(self.tcx, remaining_trait).collect();
2325:                 if remaining_trait_supertraits.contains(&child_trait) {
2326:                     child_candidate = remaining_candidate;
2327:                     child_trait = remaining_trait;
2328:                     supertraits = remaining_trait_supertraits;
2329:                     made_progress = true;
2330:                     continue;
2331:                 }
2332: 
2333:                 // `child_pick` is not a supertrait of this pick.
2334:                 // Don't bail here, since we may be comparing two supertraits
2335:                 // of a common subtrait. These two supertraits won't be related
2336:                 // at all, but we will pick them up next round when we find their
2337:                 // child as we continue iterating in this round.
2338:                 next_round.push(remaining_candidate);
2339:             }
2340: 
2341:             if made_progress {
2342:                 // If we've made progress, iterate again.
2343:                 remaining_candidates = next_round;
2344:             } else {
2345:                 // Otherwise, we must have at least two candidates which
2346:                 // are not related to each other at all.
2347:                 return None;
2348:             }
2349:         }
2350: 
2351:         Some(Pick {
2352:             item: child_candidate.item,
2353:             kind: TraitPick,
2354:             import_ids: child_candidate.import_ids.clone(),
2355:             autoderefs: 0,
2356:             autoref_or_ptr_adjustment: None,
2357:             self_ty,
2358:             unstable_candidates: vec![],
2359:             shadowed_candidates: probes
2360:                 .iter()
2361:                 .map(|(c, _)| c.item)
2362:                 .filter(|item| item.def_id != child_candidate.item.def_id)
2363:                 .collect(),
2364:             receiver_steps: None,
2365:         })
2366:     }
